-- Migration: Create mind_coach_prompts table and seed dynamic prompts for personas and pathway phases

CREATE TABLE IF NOT EXISTS public.mind_coach_prompts (
    id TEXT PRIMARY KEY,
    prompt_type TEXT NOT NULL, -- 'persona', 'phase'
    prompt_text TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- Enable RLS
ALTER TABLE public.mind_coach_prompts ENABLE ROW LEVEL SECURITY;

-- Allow read access for authenticated users & service role
CREATE POLICY "Anyone can read prompts" 
ON public.mind_coach_prompts FOR SELECT USING (true);

-- Insert Personas
ON CONFLICT (id) DO UPDATE SET prompt_text = EXCLUDED.prompt_text, updated_at = now();
